	private T2Cloner _t2Cloner;
	private T3Cloner _t3Cloner;
	private T4Cloner _t4Cloner;

	public JoinResultCloner(TLeftCloner leftCloner, T1Cloner t1Cloner, T2Cloner t2Cloner, T3Cloner t3Cloner, T4Cloner t4Cloner) {
		_leftCloner = leftCloner;
		_t1Cloner = t1Cloner;
		_t2Cloner = t2Cloner;
		_t3Cloner = t3Cloner;
		_t4Cloner = t4Cloner;
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	public void Clone(ref JoinResult<TLeft, T1, T2, T3, T4> value) {
		_leftCloner.Clone(ref Unsafe.AsRef(in value.Left));
		_t1Cloner.Clone(ref Unsafe.AsRef(in value.Right)!);
		_t2Cloner.Clone(ref Unsafe.AsRef(in value.Right2)!);
		_t3Cloner.Clone(ref Unsafe.AsRef(in value.Right3)!);
		_t4Cloner.Clone(ref Unsafe.AsRef(in value.Right4)!);
	}
}

/// <summary>
/// Cloner for JoinResult<TLeft, T1, T2, T3, T4, T5> with pluggable cloners for each field.
/// </summary>
public struct JoinResultCloner<TLeft, T1, T2, T3, T4, T5, TLeftCloner, T1Cloner, T2Cloner, T3Cloner, T4Cloner, T5Cloner> : ICloner<JoinResult<TLeft, T1, T2, T3, T4, T5>>
	where TLeftCloner : struct, ICloner<TLeft>
	where T1Cloner : struct, ICloner<T1>
	where T2Cloner : struct, ICloner<T2>
	where T3Cloner : struct, ICloner<T3>
	where T4Cloner : struct, ICloner<T4>
	where T5Cloner : struct, ICloner<T5> {

	private TLeftCloner _leftCloner;
	private T1Cloner _t1Cloner;
	private T2Cloner _t2Cloner;
	private T3Cloner _t3Cloner;
	private T4Cloner _t4Cloner;
	private T5Cloner _t5Cloner;

	public JoinResultCloner(TLeftCloner leftCloner, T1Cloner t1Cloner, T2Cloner t2Cloner, T3Cloner t3Cloner, T4Cloner t4Cloner, T5Cloner t5Cloner) {
		_leftCloner = leftCloner;
		_t1Cloner = t1Cloner;
		_t2Cloner = t2Cloner;
		_t3Cloner = t3Cloner;
		_t4Cloner = t4Cloner;
		_t5Cloner = t5Cloner;
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	public void Clone(ref JoinResult<TLeft, T1, T2, T3, T4, T5> value) {
		_leftCloner.Clone(ref Unsafe.AsRef(in value.Left));
		_t1Cloner.Clone(ref Unsafe.AsRef(in value.Right)!);
		_t2Cloner.Clone(ref Unsafe.AsRef(in value.Right2)!);
		_t3Cloner.Clone(ref Unsafe.AsRef(in value.Right3)!);
		_t4Cloner.Clone(ref Unsafe.AsRef(in value.Right4)!);
		_t5Cloner.Clone(ref Unsafe.AsRef(in value.Right5)!);
	}
}

#endregion

#region Comparers Helper

internal static class Comparers<TResult, TLeftValue, TComparer>
	where TComparer : IComparer<TLeftValue> {

	public static IComparer<TResult> Comparer(TComparer comparer) =>
		new ResultComparer(comparer);

	private sealed class ResultComparer : IComparer<TResult> {
		private readonly TComparer _comparer;

		public ResultComparer(TComparer comparer) => _comparer = comparer;

		public int Compare(TResult? x, TResult? y) {
			if (x is IJoinResult<TLeftValue> xResult && y is IJoinResult<TLeftValue> yResult)
				return _comparer.Compare(xResult.Left, yResult.Left);
			return 0;
		}
	}
}

#endregion
